{"content": "#!/usr/bin/env python3
"""A tiny calculator CLI."""
import argparse
import sys

def format_num(n):
    if n == int(n):
        return str(int(n))
    return str(n)

def main():
    parser = argparse.ArgumentParser(description="Tiny calculator CLI")
    subparsers = parser.add_subparsers(dest="command", required=True)

    # Common parser for all subcommands
    for cmd in ["add", "sub", "mul", "div"]:
        p = subparsers.add_parser(cmd)
        p.add_argument("a", type=float)
        p.add_argument("b", type=float)

    args = parser.parse_args()

    try:
        if args.command == "add":
            print(format_num(args.a + args.b))
        elif args.command == "sub":
            print(format_num(args.a - args.b))
        elif args.command == "mul":
            print(format_num(args.a * args.b))
        elif args.command == "div":
            if args.b == 0:
                print("Error: division by zero", file=sys.stderr)
                sys.exit(1)
            print(format_num(args.a / args.b))
    except Exception as e:
        print(f"Error: {e}", file=sys.stderr)
        sys.exit(1)

if __name__ == "__main__":
    main()
